INSERT INTO `ai_report` (`id`, `report_no`, `report_type`, `title`, `status`, `content_json`, `source_draft_id`, `date_start`, `date_end`, `department_id`, `created_by`, `published_by`, `published_time`, `create_time`, `update_time`, `is_deleted`) VALUES (1,'RP-20260612210047-889ddf46','customer_operation','全域客户经营分析报告（2026-06-05 至 2026-06-12）','published','{\"risks\": [], \"title\": \"全域客户经营分析报告（2026-06-05 至 2026-06-12）\", \"filters\": {\"date_end\": \"2026-06-12\", \"date_start\": \"2026-06-05\", \"department_id\": null, \"owner_user_id\": null}, \"summary\": \"本周新增线索12条，较上周期大幅上升（上周期为0），其中官网咨询3条为主要来源。完成研判分析10条，高意向占比60%，线索质量较好。成交2单，签约转化率16.7%，但平均转化天数为-0.9天，数据异常需关注。活动到场率仅12.5%，流失1条线索，原因为预算不足。客群以英国、美国硕士申请为主，预算集中在20-40万区间。\", \"sections\": [{\"content\": \"本周新增线索12条，来源渠道涵盖10个触点，其中官网咨询3条（25%）为最大来源，其次为抖音、讲座报名、线下展会等各1条。线索状态分布显示：新线索3条、跟进中6条、已签约2条、已流失1条，跟进中占比50%，反映团队正处于积极跟进阶段。环比上周期（线索为0），本周线索量增长100%，虽基数效应显著，但表明获客渠道已开始产生有效流量。\", \"heading\": \"整体线索与渠道分析\", \"metrics\": [{\"name\": \"新增线索\", \"value\": \"12\"}, {\"name\": \"官网咨询\", \"value\": \"3\"}, {\"name\": \"跟进中线索\", \"value\": \"6\"}, {\"name\": \"已签约\", \"value\": \"2\"}]}, {\"content\": \"本周完成研判分析10条，占新增线索的83.3%，研判覆盖率高。其中高意向6条（60%）、中意向3条、低意向1条，高意向客户占比较高，表明线索质量整体较好。转化漏斗方面：线索→研判转化率83.3%，研判→签约转化率20%（2/10），整体签约转化率16.7%（2/12）。高意向客户中仍有4条未签约，后续跟进空间较大。\", \"heading\": \"研判转化与高意向分析\", \"metrics\": [{\"name\": \"研判分析数\", \"value\": \"10\"}, {\"name\": \"高意向占比\", \"value\": \"60%\"}, {\"name\": \"签约转化率\", \"value\": \"16.7%\"}]}], \"tool_error\": \"\", \"report_type\": \"customer_operation\", \"source_data\": {\"date_end\": \"2026-06-12\", \"new_leads\": 12, \"date_start\": \"2026-06-05\", \"lead_trend\": {\"label\": \"上升\", \"delta_pct\": 100}, \"prev_period\": {\"leads\": 0, \"events\": 0, \"analysis\": 0, \"date_end\": \"2026-06-05\", \"date_start\": \"2026-05-29\"}, \"report_type\": \"customer_operation\", \"signed_count\": 2, \"department_id\": null, \"owner_user_id\": null, \"analysis_records\": 10, \"cluster_breakdown\": [{\"count\": 1, \"label\": \"美国读硕士+硕士+31万\", \"budget_range\": \"31万\", \"target_country\": \"美国读硕士\", \"target_program\": \"硕士\"}, {\"count\": 1, \"label\": \"新加坡读硕士+硕士+25万\", \"budget_range\": \"25万\", \"target_country\": \"新加坡读硕士\", \"target_program\": \"硕士\"}, {\"count\": 1, \"label\": \"英国+硕士申请+30-40万\", \"budget_range\": \"30-40万\", \"target_country\": \"英国\", \"target_program\": \"硕士申请\"}, {\"count\": 1, \"label\": \"美国+硕士申请+50-60万\", \"budget_range\": \"50-60万\", \"target_country\": \"美国\", \"target_program\": \"硕士申请\"}, {\"count\": 1, \"label\": \"新加坡+硕士申请+25-35万\", \"budget_range\": \"25-35万\", \"target_country\": \"新加坡\", \"target_program\": \"硕士申请\"}], \"lost_reason_counts\": {\"预算不足，暂不考虑付费服务\": 1}, \"portrait_breakdown\": {\"budget_range_counts\": {\"25万\": 1, \"31万\": 1, \"10-20万\": 1, \"20-30万\": 2, \"25-35万\": 1, \"30-40万\": 2, \"35-45万\": 1, \"40-50万\": 1, \"50-60万\": 1, \"60万以上\": 1}, \"target_country_counts\": {\"德国\": 1, \"美国\": 2, \"英国\": 3, \"香港\": 1, \"加拿大\": 1, \"新加坡\": 1, \"澳大利亚\": 1, \"美国读硕士\": 1, \"新加坡读硕士\": 1}, \"target_program_counts\": {\"硕士\": 2, \"博士申请\": 1, \"本科申请\": 1, \"硕士申请\": 6, \"背景提升\": 1, \"作品集辅导\": 1}, \"education_level_counts\": {\"本科\": 10, \"硕士\": 1, \"高中\": 1}}, \"avg_conversion_days\": -0.9, \"event_registrations\": 10, \"churn_stage_breakdown\": {\"lost\": 1}, \"lead_source_breakdown\": {\"抖音\": 1, \"合作渠道\": 1, \"官网咨询\": 3, \"抖音表单\": 1, \"电话咨询\": 1, \"线下展会\": 1, \"讲座报名\": 1, \"公众号咨询\": 1, \"小红书私信\": 1, \"老客户推荐\": 1}, \"lead_status_breakdown\": {\"new\": 3, \"lost\": 1, \"signed\": 2, \"following\": 6}, \"churn_source_breakdown\": {\"公众号咨询\": 1}, \"signed_conversion_rate\": 16.7, \"signed_source_breakdown\": {\"抖音\": 1, \"线下展会\": 1}, \"analysis_result_breakdown\": {\"low\": 1, \"high\": 6, \"medium\": 3}, \"event_registration_breakdown\": {\"attended\": 1, \"cancelled\": 1, \"registered\": 8}}, \"source_refs\": [], \"recommendations\": [], \"tool_status_code\": 200, \"tool_call_success\": true}',75,'2026-06-05','2026-06-12',NULL,1,1,'2026-06-12 21:00:57','2026-06-12 21:00:48','2026-06-12 21:00:57',0);
