INSERT INTO `employee_daily_report` (`id`, `employee_id`, `department_id`, `report_date`, `raw_content`, `summary`, `key_progress`, `risks`, `tomorrow_plan`, `report_status`, `create_time`, `update_time`, `is_delete`) VALUES (1,1,1,'2026-06-09','今天召开项目周会，确认企业智能助手优先上线客户录入、日报和查询功能。','确认企业智能助手第一阶段范围。','完成模块优先级确认；协调销售与教务资源。','学生端联动接口需要尽快确定。','明天跟进接口负责人和演示数据准备。','submitted','2026-06-10 12:03:21','2026-06-10 12:03:21',0),(2,2,2,'2026-06-09','今天跟进王一鸣、李思琪、陈子涵三个客户，陈子涵已签约，王一鸣约了方案沟通。','跟进3名客户，其中1名已签约。','陈子涵完成签约；王一鸣确定方案沟通时间。','李思琪托福成绩未补充，转化节奏偏慢。','明天重点跟进王一鸣和李思琪。','submitted','2026-06-10 12:03:21','2026-06-10 12:03:21',0),(3,3,3,'2026-06-09','处理张明请假申请，录入周琪雅思阅读成绩，并查看两名学生学习进度。','完成请假和成绩相关教务工作。','张明请假审批完成；周琪成绩已录入。','部分学生成绩录入不完整。','明天核对本周模考成绩。','submitted','2026-06-10 12:03:21','2026-06-10 12:03:21',0),(4,4,4,'2026-06-09','回复官网咨询12条，登记吴昊线索，协助客户完成讲座报名。','完成客服咨询接待和活动报名支持。','新增吴昊线索；完成3个活动咨询回复。','部分客户对费用政策反复询问。','明天整理费用FAQ。','submitted','2026-06-10 12:03:21','2026-06-10 12:03:21',0),(5,5,5,'2026-06-09','跟进张浩然、赵可欣、郑文博三个市场渠道客户，赵可欣等待合同确认。','市场渠道客户持续推进。','赵可欣面谈后意向较强；郑文博已收到项目清单。','张浩然家长关注移民政策，需签证部支持。','明天邀请签证顾问一起沟通。','submitted','2026-06-10 12:03:21','2026-06-10 12:03:21',0),(6,6,6,'2026-06-09','审核李雨文书初稿，更新刘洋博士申请材料清单。','完成文书审核和博士申请材料整理。','李雨文书初稿已反馈；刘洋材料清单更新。','刘洋推荐信时间较紧。','明天联系学生确认推荐人信息。','submitted','2026-06-10 12:03:21','2026-06-10 12:03:21',0),(7,7,7,'2026-06-09','解答张浩然加拿大签证政策问题，跟进陈安签证材料。','完成签证咨询和材料跟进。','张浩然签证政策已说明；陈安材料缺口已列明。','陈安资金证明还未准备。','明天提醒学生补充资金证明。','submitted','2026-06-10 12:03:21','2026-06-10 12:03:21',0),(8,8,8,'2026-06-09','核对陈子涵合同收款情况，处理一条退费政策咨询。','完成合同收款核对和费用咨询。','陈子涵合同收款已确认。','退费政策说明需要客服同步统一口径。','明天更新费用相关FAQ。','submitted','2026-06-10 12:03:21','2026-06-10 12:03:21',0),(9,9,9,'2026-06-09','整理企业智能助手演示流程，准备客户、日报、请假、投诉测试数据。','完成系统演示流程和测试数据准备。','明确演示链路；梳理测试数据字段。','部分模块接口尚未联调。','明天推动接口联调。','submitted','2026-06-10 12:03:21','2026-06-10 12:03:21',0),(10,10,10,'2026-06-09','跟进两名心理风险学生，完成王璐情绪访谈记录。','完成学生心理关怀跟进。','王璐情绪访谈完成；张明压力情况已缓解。','刘洋近期压力较高，需要持续观察。','明天安排刘洋关怀沟通。','submitted','2026-06-10 12:03:21','2026-06-10 12:03:21',0);
