INSERT INTO `faq_qa` (`id`, `module_scope`, `category`, `question`, `answer`, `keywords`, `status`, `sort_order`, `create_time`, `update_time`, `is_delete`) VALUES (1,'enterprise_assistant','客户管理','新员工如何录入意向客户？','进入企业智能助手后，输入或口述客户姓名、联系方式、意向国家、目标项目等信息，系统会生成确认卡片，确认后写入CRM。','客户录入,CRM,意向客户','enabled',1,'2026-06-10 12:03:21','2026-06-10 12:03:21',0),(2,'enterprise_assistant','日报','员工日报怎么提交？','员工可以直接口述当天工作内容，AI会自动整理为摘要、关键进展、风险问题和明日计划，确认后提交。','日报,口述日报,提交日报','enabled',2,'2026-06-10 12:03:21','2026-06-10 12:03:21',0),(3,'enterprise_assistant','审批','请假申请怎么审批？','老师可以询问“我有哪些待审批请假”，查看学生请假详情后点击通过或驳回，审批结果会更新到请假申请表。','请假,审批,企业助手','enabled',3,'2026-06-10 12:03:21','2026-06-10 12:03:21',0),(4,'enterprise_assistant','投诉处理','投诉反馈如何处理？','员工可以查询自己负责的待处理投诉，补充处理方案并更新状态为处理中、已解决或已关闭。','投诉,反馈,工单','enabled',4,'2026-06-10 12:03:21','2026-06-10 12:03:21',0),(5,'customer_service','公司信息','你们主要提供哪些服务？','我们主要提供留学申请、语言培训、背景提升、签证指导和海外生活支持等服务。','服务,业务,留学申请','enabled',5,'2026-06-10 12:03:21','2026-06-10 12:03:21',0),(6,'customer_service','费用','服务费用大概是多少？','费用会根据目标国家、申请阶段和服务内容不同而变化，建议先完成需求评估后获取具体方案。','费用,价格,服务费','enabled',6,'2026-06-10 12:03:21','2026-06-10 12:03:21',0),(7,'student_assistant','海外生活','刚到海外后需要优先办理什么？','建议优先完成住宿确认、电话卡办理、银行卡办理、学校注册和当地紧急联系方式保存。','海外生活,入境,生活指南','enabled',7,'2026-06-10 12:03:21','2026-06-10 12:03:21',0),(8,'student_assistant','学业','论文DDL怎么查询？','可以在学生智能助手中询问“我的论文截止时间是什么时候”，系统会根据学业考务事件返回相关节点。','论文DDL,考试,学业','enabled',8,'2026-06-10 12:03:21','2026-06-10 12:03:21',0),(9,'common','组织架构','如何查询部门负责人？','可以向企业智能助手提问“某某部门负责人是谁”，系统会根据部门表和员工档案返回负责人信息。','组织架构,负责人,部门','enabled',9,'2026-06-10 12:03:21','2026-06-10 12:03:21',0),(10,'common','系统使用','如果AI识别的信息不对怎么办？','在确认卡片中点击修改信息，调整后再确认提交；涉及写库操作时不要跳过确认步骤。','AI识别,确认卡片,修改','enabled',10,'2026-06-10 12:03:21','2026-06-10 12:03:21',0);
/*!40000 ALTER TABLE `faq_qa` ENABLE KEYS */;
UNLOCK TABLES;

